// Load libraries, create express and a new instance of the Express application.

var express = require('express');
const sgMail = require('@sendgrid/mail')
sgMail.setApiKey('<KEY>');
console.log(sgMail)


var app = express();


// Send a new email via SendGrid using their API - send an email to <EMAIL> with the subject "This is a test email." Use the following payload: 
const msg = {
  to: '<EMAIL>', 
  from: '<EMAIL>', // Your email here 
  subject: 'This is a test email.',
  text: 'Sending this test email using SendGrid.',
};


// Handle POST requests.
app.post('/', function(request, response) {

    sgMail
        .send(msg)
        .then(() => {
          console.log('Email sent')
          response.status(200).end()
        })
        .catch((error) => {
            console.error(error);
            return response.status(400).end();
 });
});

// Create a port variable using environment variables or hardcode 81 as fallback.
var port = Number(process.env.PORT || '3000');

// Configure app to listen on port 81.
app.listen(port, function() {
    console.log('Listening on port %s', port);
  });